// Section: in_list_literal
// Set membership tests using list literals and the 'in' operator
mod in_list_literal {
    use conformance::runner::run_test;
    use dedent::dedent;

    // Test: elem_not_in_empty_list
    #[test]
    fn elem_not_in_empty_list() {
        run_test(&dedent!(
            r#"
                expr: "'empty' in []"
                value { bool_value: false }
            "#
        ));
    }

    // Test: elem_in_list
    #[test]
    fn elem_in_list() {
        run_test(&dedent!(
            r#"
                expr: "'elem' in ['elem', 'elemA', 'elemB']"
                value { bool_value: true }
            "#
        ));
    }

    // Test: elem_not_in_list
    #[test]
    fn elem_not_in_list() {
        run_test(&dedent!(
            r#"
                expr: "'not' in ['elem1', 'elem2', 'elem3']"
                value { bool_value: false }
            "#
        ));
    }

    // Test: elem_in_mixed_type_list
    #[test]
    fn elem_in_mixed_type_list() {
        run_test(&dedent!(
            r#"
                description: "Set membership tests should succeed if the 'elem' exists in a mixed element type list."
                expr: "'elem' in [1, 'elem', 2]"
                value { bool_value: true }
            "#
        ));
    }

    // Test: elem_in_mixed_type_list_cross_type
    #[test]
    fn elem_in_mixed_type_list_cross_type() {
        run_test(&dedent!(
            r#"
                description: "Set membership tests should return false due to the introduction of heterogeneous-equality. Set membership via 'in' is equivalent to the macro exists() behavior."
                expr: "'elem' in [1u, 'str', 2, b'bytes']"
                value: { bool_value: false }
            "#
        ));
    }
}

// Section: in_map_literal
// Set membership tests using map literals and the 'in' operator
mod in_map_literal {
    use conformance::runner::run_test;
    use dedent::dedent;

    // Test: key_not_in_empty_map
    #[test]
    fn key_not_in_empty_map() {
        run_test(&dedent!(
            r#"
                expr: "'empty' in {}"
                value { bool_value: false }
            "#
        ));
    }

    // Test: key_in_map
    #[test]
    fn key_in_map() {
        run_test(&dedent!(
            r#"
                expr: "'key' in {'key':'1', 'other':'2'}"
                value { bool_value: true }
            "#
        ));
    }

    // Test: key_not_in_map
    #[test]
    fn key_not_in_map() {
        run_test(&dedent!(
            r#"
                expr: "'key' in {'lock':1, 'gate':2}"
                value { bool_value: false }
            "#
        ));
    }

    // Test: key_in_mixed_key_type_map
    #[test]
    fn key_in_mixed_key_type_map() {
        run_test(&dedent!(
            r#"
                description: "Map keys are of mixed type, but since the key is present the result is true."
                expr: "'key' in {3:3.0, 'key':2u}"
                value { bool_value: true }
            "#
        ));
    }

    // Test: key_in_mixed_key_type_map_cross_type
    #[test]
    fn key_in_mixed_key_type_map_cross_type() {
        run_test(&dedent!(
            r#"
                expr: "'key' in {1u:'str', 2:b'bytes'}"
                value: { bool_value: false }
            "#
        ));
    }
}

// Section: bound
// Comparing bound variables with literals or other variables
mod bound {
    use conformance::runner::run_test;
    use dedent::dedent;

    // Test: bytes_gt_left_false
    #[test]
    fn bytes_gt_left_false() {
        run_test(&dedent!(
            r#"
                expr: "x > b'\x00'"
                value: { bool_value: false }
                type_env: {
                  name: "x"
                  ident: { type: { primitive: BYTES } }
                }
                bindings: {
                  key: "x"
                  value: { value: { bytes_value: "\x00" } }
                }
            "#
        ));
    }

    // Test: int_lte_right_true
    #[test]
    fn int_lte_right_true() {
        run_test(&dedent!(
            r#"
                expr: "123 <= x"
                value: { bool_value: true }
                type_env: {
                  name: "x"
                  ident: { type: { primitive: INT64 } }
                }
                bindings: {
                  key: "x"
                  value: { value: { int64_value: 124 } }
                }
            "#
        ));
    }

    // Test: bool_lt_right_true
    #[test]
    fn bool_lt_right_true() {
        run_test(&dedent!(
            r#"
                expr: "false < x"
                value: { bool_value: true }
                type_env: {
                  name: "x"
                  ident: { type: { primitive: BOOL } }
                }
                bindings: {
                  key: "x"
                  value: { value: { bool_value: true } }
                }
            "#
        ));
    }

    // Test: double_ne_left_false
    #[test]
    fn double_ne_left_false() {
        run_test(&dedent!(
            r#"
                expr: "x != 9.8"
                value: { bool_value: false }
                type_env: {
                  name: "x"
                  ident: { type: { primitive: DOUBLE } }
                }
                bindings: {
                  key: "x"
                  value: { value: { double_value: 9.8 } }
                }
            "#
        ));
    }

    // Test: map_ne_right_false
    #[test]
    fn map_ne_right_false() {
        run_test(&dedent!(
            r#"
                expr: "{'a':'b','c':'d'} != x"
                value: { bool_value: false }
                type_env: {
                  name: "x"
                  ident: {
                    type: {
                      map_type: {
                        key_type: { primitive: STRING }
                        value_type: { primitive: STRING }
                      }
                    }
                  }
                }
                bindings: {
                  key: "x"
                  value: {
                    value: {
                      map_value {
                        entries {
                          key: { string_value: "c" }
                          value: { string_value: "d" }
                        }
                        entries {
                          key: { string_value: "a" }
                          value: { string_value: "b" }
                        }
                      }
                    }
                  }
                }
            "#
        ));
    }

    // Test: null_eq_left_true
    #[test]
    fn null_eq_left_true() {
        run_test(&dedent!(
            r#"
                description: "A comparison _==_ against null only binds if the type is determined to be null or we skip the type checking"
                expr: "x == null"
                value: { bool_value: true }
                type_env: {
                  name: "x"
                  ident: { type: { null: NULL_VALUE } }
                }
                bindings: {
                  key: "x"
                  value: { value: { null_value: NULL_VALUE } }
                }
            "#
        ));
    }

    // Test: list_eq_right_false
    #[test]
    fn list_eq_right_false() {
        run_test(&dedent!(
            r#"
                expr: "[1, 2] == x"
                value: { bool_value: false }
                type_env: {
                  name: "x"
                  ident: {
                    type: {
                      list_type: {
                        elem_type: { primitive: INT64 }
                      }
                    }
                  }
                }
                bindings: {
                  key: "x"
                  value: {
                    value: {
                      list_value {
                        values: { int64_value: 2 }
                        values: { int64_value: 1 }
                      }
                    }
                  }
                }
            "#
        ));
    }

    // Test: string_gte_right_true
    #[test]
    fn string_gte_right_true() {
        run_test(&dedent!(
            r#"
                expr: "'abcd' >= x"
                value: { bool_value: true }
                type_env: {
                  name: "x"
                  ident: {
                    type: { primitive: STRING }
                  }
                }
                bindings: {
                  key: "x"
                  value: { value: { string_value: "abc" } }
                }
            "#
        ));
    }

    // Test: uint_eq_right_false
    #[test]
    fn uint_eq_right_false() {
        run_test(&dedent!(
            r#"
                expr: "999u == x"
                value: { bool_value: false }
                type_env: {
                  name: "x"
                  ident: {
                    type: { primitive: UINT64 }
                  }
                }
                bindings: {
                  key: "x"
                  value: { value: { uint64_value: 1000 } }
                }
            "#
        ));
    }

    // Test: null_lt_right_no_such_overload
    #[test]
    fn null_lt_right_no_such_overload() {
        run_test(&dedent!(
            r#"
                description: "There is no _<_ operation for null, even if both operands are null"
                expr: "null < x"
                eval_error: {
                  errors: { message: "no such overload" }
                }
                disable_check: true
                bindings: {
                  key: "x"
                  value: { value: { null_value: NULL_VALUE } }
                }
            "#
        ));
    }
}
